function _if(cond: boolean, errorMsg: string): boolean {
    if (!cond) console.error(errorMsg);
    return cond;
}

function checkRequiredIds(): boolean {
    const requiredIds = [
        'wstep', 'podmiot', 'url', 'data-publikacja', 'data-aktualizacja', 'status', 'data-sporzadzenie', 'kontakt', 'osoba', 'email', 'telefon', 'procedura', 'architektura'
    ].map(id => `a11y-${id}`);
    // ? a11y-audytor
    const notFoundIds = requiredIds.filter(id => !document.getElementById(id));
    return _if(notFoundIds.length == 0, `W deklaracji brakuje elementów o następujących ID: ${notFoundIds.join(', ')}.`);
}

function verifyStatus(): boolean {
    const statusOptions = [
        'Strona internetowa jest zgodna z ustawą z dnia 4 kwietnia 2019 r. o dostępności cyfrowej stron internetowych i aplikacji mobilnych podmiotów publicznych.',
        'Strona internetowa jest częściowo zgodna z ustawą z dnia 4 kwietnia 2019 r. o dostępności cyfrowej stron internetowych i aplikacji mobilnych podmiotów publicznych z powodu niezgodności lub wyłączeń wymienionych poniżej.',
        'Strona internetowa jest niezgodna z ustawą z dnia 4 kwietnia 2019 r. o dostępności cyfrowej stron internetowych i aplikacji mobilnych podmiotów publicznych. Niezgodność (niezgodności) lub wyłączenia wymieniono poniżej.'
    ];
    const statusContent = document.getElementById('a11y-status')?.textContent;

    return _if(statusOptions.indexOf(statusContent || '') >= 0, 'Nieprawidłowy status.');
}

function verifyIntroduction(): boolean {
    const introNode = document.getElementById('a11y-wstep');
    if (introNode == null) return false;
    const expectedIntroductionText = "zobowiązuje się zapewnić dostępność swojej strony internetowej zgodnie z przepisami ustawy z dnia 4 kwietnia 2019 r. o dostępności cyfrowej stron internetowych i aplikacji mobilnych podmiotów publicznych. Oświadczenie w sprawie dostępności ma zastosowanie do strony internetowej";
    const children = Array.from(introNode.childNodes);
    const hasPodmiot = _if(children.length >= 1 && children[0] instanceof HTMLElement && children[0].id == 'a11y-podmiot', 'Nie znaleziono podmiotu na początku wstępu');
    const hasWebsite = _if(children.length >= 3 && children[2] instanceof HTMLElement && children[2].id == 'a11y-url', 'Nie znaleziono strony internetowej na końcu wstępu');
    const isWebsiteUrl = hasWebsite && _if(children[2] instanceof HTMLAnchorElement && children[2].href != "", "Nie zdefiniowano URL strony internetowej");
    const hasIntroText = _if(children.length >= 2 && children[1].textContent?.trim() == expectedIntroductionText, `Niepoprawny tekst wstępu: ${children.at(1)?.textContent}`);
    return hasIntroText && hasPodmiot && hasWebsite && isWebsiteUrl;
}

function verifyDates(): boolean {
    const regex = /\d{4}-\d{2}-\d{2}/;
    const dataPublikacji = document.getElementById('a11y-data-publikacja')?.textContent;
    const dataAktualizacji = document.getElementById('a11y-data-aktualizacja')?.textContent;
    const dataSporzadzenia = document.getElementById('a11y-data-sporzadzenie')?.textContent;
    const publikacjaOk = _if(dataPublikacji?.match(regex) != null, `Data publikacji nie jest w formacie RRRR-MM-DD: ${dataPublikacji}`);
    const aktualizacjaOk = _if(dataAktualizacji?.match(regex) != null, `Data aktualizacji nie jest w formacie RRRR-MM-DD: ${dataAktualizacji}`);
    const sporzadzenieOk = _if(dataSporzadzenia?.match(regex) != null, `Data sporządzenia nie jest w formacie RRRR-MM-DD: ${dataSporzadzenia}`);
    return publikacjaOk && aktualizacjaOk && sporzadzenieOk;
}

function verifyContact(): boolean {
    const kontaktNode = document.getElementById('a11y-kontakt');
    const kontaktContent = kontaktNode?.textContent;
    return _if(kontaktNode instanceof HTMLHeadingElement && kontaktContent == 'Informacje zwrotne i dane kontaktowe', 'Nieprawidłowa zawartość elementu #a11y-kontakt');
}

function findDeclarationBaseNode(node: HTMLElement): Optional<HTMLElement> {
    const childWithText = Array.from(node.children).find(el => el.textContent?.includes("Deklarację sporządzono na podstawie"));
    if (!childWithText) {
        return null;
    } else if (childWithText?.textContent?.trim()?.indexOf("Deklarację sporządzono na podstawie") == 0) {
        return childWithText as HTMLElement;
    } else {
        return findDeclarationBaseNode(childWithText as HTMLElement);
    }
}

function verifyAudit(): boolean {
    const root = document.getElementById('a11y-deklaracja')?.parentElement;
    if (!root) return false;
    const node = findDeclarationBaseNode(root);
    const podstawaOk = _if(node != null, "Nie znaleziono podstawy sporządzenia deklaracji dostępności");
    const audytorOk = _if(node != null && node.querySelector('#a11y-audytor') != null, "Nie znaleziono audytora");
    if (node?.textContent?.includes("samooceny")) {
        console.warn("Deklaracja sporządzona na podstawie samooceny");
    }
    return podstawaOk && audytorOk;
}

/**
 * @returns true if Accessibility Statement is correct,
 * otherwise message containing found errors
 *
 * Validation based on https://www.gov.pl/web/dostepnosc-cyfrowa/publikowanie-deklaracji-dostepnosci
 */
function validateAccessibilityStatement(): boolean {
    // const pageBody = document.querySelector('main-panel > [slot=page-body]');
    const checks = [checkRequiredIds, verifyIntroduction, verifyDates, verifyStatus, verifyContact, verifyAudit];
    return checks.map(check => check()).every(c => c);
}

/**
 * Exported function allowing to manually run AS validation
 */
export function checkAccessibilityStatement(): boolean {
    return validateAccessibilityStatement();
}
